#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 1000000
#define MAX_Q 1000000

// Define the structure for a city
typedef struct {
    int tastiness;
    int parent;
} City;

// Define the structure for a query
typedef struct {
    int initialTastiness;
    int destination;
} Query;

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        City cities[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &cities[i].tastiness);
        }
        for (int i = 1; i < N; i++) {
            scanf("%d", &cities[i].parent);
        }
        int Q;
        scanf("%d", &Q);
        Query queries[Q];
        for (int i = 0; i < Q; i++) {
            scanf("%d %d", &queries[i].initialTastiness, &queries[i].destination);
        }
        for (int i = 0; i < Q; i++) {
            int currentTastiness = queries[i].initialTastiness;
            int currentCity = 0;
            int count = 0;
            while (currentCity != queries[i].destination - 1) {
                if (cities[currentCity].tastiness > currentTastiness) {
                    currentTastiness = cities[currentCity].tastiness;
                    count++;
                }
                currentCity = cities[currentCity].parent - 1;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

