import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int[] tastiness = new int[N];
            for (int i = 0; i < N; i++) {
                tastiness[i] = scanner.nextInt();
            }
            int[] parent = new int[N];
            for (int i = 1; i < N; i++) {
                parent[i] = scanner.nextInt();
            }
            int Q = scanner.nextInt();
            int[] initialTastiness = new int[Q];
            int[] destination = new int[Q];
            for (int i = 0; i < Q; i++) {
                initialTastiness[i] = scanner.nextInt();
                destination[i] = scanner.nextInt();
            }
            for (int i = 0; i < Q; i++) {
                int currentTastiness = initialTastiness[i];
                int currentCity = 0;
                int count = 0;
                while (currentCity != destination[i] - 1) {
                    if (tastiness[currentCity] > currentTastiness) {
                        currentTastiness = tastiness[currentCity];
                        count++;
                    }
                    currentCity = parent[currentCity] - 1;
                }
                System.out.println(count);
            }
        }
    }
}

